int valid(char *s,int l,int r)
{
    struct node
    {
        char c;
        int val;
    };
    int i;
    int j=-1,n=(r-l)+1;
    struct node a[n];
    int k=0;
    int m=0;
    int c=0;
    if(n>0)
    {
        for(i=l-1;i<r;++i)   
        {
            if(j==-1)
            {
                a[++j].c=s[i];
                a[j].val=i;
            }
            else
            { 
                if(j>-1 && a[j].c=='(' && s[i]==')')
                {
                    --j;
                }
                else
                {
                    a[++j].c=s[i];
                    a[j].val=i;
                }
            }
        }
        k=0;
        for(i=l-1;i<r;i++)
        {
            if(k<=j)
            {
                if(i==a[k].val)
                {
                    if(m<=c)
                        m=c;
                    c=0;
                    if(k<j)
                        k++;
                }    
                else
                    ++c;
            }
            else
                ++c;
        }
        if(m<=c)
            m=c;
    }
    return m;
