class Codechef
{
    public static void main (String[] args) throws java.lang.Exception
    {
        // your code goes here
        Scanner scn = new Scanner(System.in);

        int t = scn.nextInt();

        while(t-- > 0){
            String s = scn.next();

            int n = scn.nextInt();
            int ans[] = new int[n]; 

            for(int i = 0 ; i < n; i++){
                int a = scn.nextInt();
                int b = scn.nextInt();

                ans[i] = find(a, b, s);
            }

            for(int i : ans){
                System.out.print(i + " ");
            }
            System.out.println("");

        }

    }

    public static int find(int a, int b, String s){
        Stack<Integer> st = new Stack<>();

        for(int i = a-1; i< b; i++){
            if(s.charAt(i) == '('){
                st.push(i);
            } else{
                if(!st.empty() && s.charAt(st.peek()) == '('){
                    st.pop();
                } else {
                    st.push(i);
                }
            }
        }

        int maxLen = 0;
        int end=b;

        while(!st.empty()){
            int startTerminal  = st.pop();
            maxLen = Math.max(maxLen, end - startTerminal -1);
            end = startTerminal;
        }

        return Math.max(end - a +1, maxLen);
    }











